const appendMediaToken = (url) => {
    if (!url) return '';
    const token = localStorage.getItem('token') || '';
    if (!token) return url;

    try {
        const parsed = new URL(url, window.location.origin);
        if (!parsed.pathname.startsWith('/api/chat/media')) return url;
        parsed.searchParams.set('token', token);
        if (/^https?:\/\//i.test(url)) return parsed.toString();
        return `${parsed.pathname}${parsed.search}${parsed.hash}`;
    } catch (_) {
        if (!String(url).includes('/api/chat/media')) return url;
        const withoutToken = String(url)
            .replace(/([?&])token=[^&#]*&?/i, '$1')
            .replace(/[?&]$/g, '');
        return withoutToken.includes('?')
            ? `${withoutToken}&token=${encodeURIComponent(token)}`
            : `${withoutToken}?token=${encodeURIComponent(token)}`;
    }
};

const buildMediaProxyUrl = (rawPath) => {
    if (!rawPath) return '';
    const raw = String(rawPath);
    return (() => {
        try {
            const parsed = new URL(raw, window.location.origin);
            if (parsed.pathname.startsWith('/uploads/')) {
                const mediaApiPath = `/api/chat/media?path=${encodeURIComponent(parsed.pathname)}`;
                return appendMediaToken(mediaApiPath);
            }
            return appendMediaToken(`${parsed.pathname || raw}${parsed.search || ''}`);
        } catch (_) {
            const normalized = raw.startsWith('/') ? raw : `/${raw.replace(/^\/+/, '')}`;
            if (normalized.startsWith('/uploads/')) {
                const mediaApiPath = `/api/chat/media?path=${encodeURIComponent(normalized)}`;
                return appendMediaToken(mediaApiPath);
            }
            return appendMediaToken(normalized);
        }
    })();
};

const getMediaUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('blob:') || path.startsWith('data:')) return path;
    if (path.startsWith('http')) {
        try {
            const parsed = new URL(path);
            if (parsed.pathname.startsWith('/uploads/')) {
                return buildMediaProxyUrl(`${parsed.pathname}${parsed.search || ''}`) || null;
            }
            if (parsed.pathname.startsWith('/api/chat/media')) {
                return appendMediaToken(`${parsed.pathname}${parsed.search || ''}`);
            }
        } catch (_) { }
        return appendMediaToken(path);
    }
    if (path.startsWith('/uploads/')) {
        return buildMediaProxyUrl(path) || null;
    }
    if (path.startsWith('/api/chat/media')) {
        return appendMediaToken(path);
    }
    const base = axios.defaults.baseURL || '';
    const resolved = `${base.replace(/\/$/, '')}/${path.replace(/^\//, '')}`;
    return appendMediaToken(resolved) || null;
};

const isPersistentMessageObjectId = (value) => /^[a-f0-9]{24}$/i.test(String(value || '').trim());

const isManagedAppMediaPath = (rawPath = '') => {
    const value = String(rawPath || '').trim();
    if (!value || value.startsWith('blob:') || value.startsWith('data:')) return false;
    if (value.startsWith('/uploads/') || value.startsWith('/api/chat/media')) return true;
    if (!/^https?:\/\//i.test(value)) return true;

    try {
        const parsed = new URL(value);
        return parsed.pathname.startsWith('/uploads/') || parsed.pathname.startsWith('/api/chat/media');
    } catch (_) {
        return false;
    }
};

const getUploadMediaDuration = async (mediaFile) => {
    if (!mediaFile || !(mediaFile instanceof Blob || mediaFile instanceof File)) return 0;
    const mimeType = String(mediaFile.type || '').toLowerCase();
    const isVideo = mimeType.startsWith('video/');
    const isAudio = mimeType.startsWith('audio/');
    if (!isVideo && !isAudio) return 0;

    const objectUrl = URL.createObjectURL(mediaFile);
    const mediaEl = document.createElement(isVideo ? 'video' : 'audio');
    mediaEl.preload = 'metadata';
    mediaEl.muted = true;
    mediaEl.playsInline = true;

    try {
        const duration = await new Promise((resolve) => {
            let settled = false;
            const cleanup = () => {
                mediaEl.onloadedmetadata = null;
                mediaEl.onerror = null;
                mediaEl.removeAttribute('src');
                mediaEl.load?.();
                URL.revokeObjectURL(objectUrl);
            };
            const finish = (value) => {
                if (settled) return;
                settled = true;
                cleanup();
                resolve(value);
            };

            mediaEl.onloadedmetadata = () => {
                const nextDuration = Number(mediaEl.duration || 0);
                finish(Number.isFinite(nextDuration) && nextDuration > 0 ? Math.round(nextDuration) : 0);
            };
            mediaEl.onerror = () => finish(0);
            mediaEl.src = objectUrl;
        });

        return duration;
    } catch (_) {
        URL.revokeObjectURL(objectUrl);
        return 0;
    }
};



